-- Insertar preguntas del Examen de Matemática Aplicada al Mecanizado Industrial
do $$
declare
  tema_0 uuid;
  tema_1 uuid;
  tema_2 uuid;
  tema_3 uuid;
begin
  select id into tema_0 from temas where nombre = 'Inclinación de Ángulos y Conicidades';
  select id into tema_1 from temas where nombre = 'Tipos y Cálculo de Roscas';
  select id into tema_2 from temas where nombre = 'Cálculo de RPM y Velocidades de Corte';
  select id into tema_3 from temas where nombre = 'Conversión de Unidades y Metrología';
end $$;